const leads = $input.all().map(i => i.json);
const results = [];
for (const lead of leads) {
  const days = Math.floor((Date.now() - new Date(lead.created_at)) / (1000*60*60*24));
  const score = lead.score || 0;
  let tier = score >= 70 ? 'hot' : score >= 40 ? 'warm' : 'cold';
  let sendDay = false;
  if (tier === 'hot' && [1,3,5].includes(days)) sendDay = true;
  if (tier === 'warm' && [2,5,10].includes(days)) sendDay = true;
  if (tier === 'cold' && [3,7,14,30].includes(days)) sendDay = true;
  if (!sendDay) continue;
  const subjects = { hot: [`Your TotalGuard quote is ready, ${lead.first_name}`, `Still thinking it over? We saved your spot`, `Final notice: lock in your lawn care rate`], warm: [`Madison lawn tips — from TotalGuard`, `How TotalGuard protects your lawn all season`, `Your neighbors are loving their TotalGuard service`], cold: [`Free lawn care tips from TotalGuard`, `Seasonal reminder from TotalGuard Yard Care`, `When you're ready, we're here`] };
  const seqIdx = tier === 'hot' ? [1,3,5].indexOf(days) : tier === 'warm' ? [2,5,10].indexOf(days) : [3,7,14,30].indexOf(days);
  const subject = subjects[tier][Math.min(seqIdx, subjects[tier].length-1)];
  results.push({ json: { ...lead, tier, days, subject } });
}
return results;
